// src/repository.ts
init_shim();
var LocalStorageRepository = class {
  constructor(name) {
    this.name = name;
  }
  /**
   * Save data to local storage. If data with the same key exists, it will be merged.
   * @param data
   */
  save(address, data) {
    this.run(() => {
      let all = this.getAll(address);
      all = { [address]: { ...all, ...data } };
      localStorage.setItem(this.name, JSON.stringify(all));
    });
  }
  /**
   * get data from local storage
   * @param key
   * @returns
   */
  get(address, key) {
    const data = this.getAll(address);
    if (!data) {
      return null;
    }
    return data[key];
  }
  /**
   * get all data from local storage
   * @param address
   * @returns
   */
  getAll(address) {
    try {
      const data = localStorage.getItem(this.name);
      if (!data) {
        return null;
      }
      return JSON.parse(data)[address];
    } catch (error) {
      console.error(error);
      return null;
    }
  }
  clear(address) {
    this.run(() => {
      const all = this.getAll(address);
      if (!all) {
        return;
      }
      delete all[address];
      localStorage.setItem(this.name, JSON.stringify(all));
    });
  }
  update(address, key, data) {
    this.run(() => {
      const all = this.getAll(address);
      all[key] = data;
      localStorage.setItem(this.name, JSON.stringify(all));
    });
  }
  remove(address, key) {
    this.run(() => {
      const all = this.getAll(address);
      delete all[key];
      localStorage.setItem(this.name, JSON.stringify(all));
    });
  }
  run(cb) {
    if (typeof window !== "undefined" && typeof localStorage !== "undefined") {
      cb();
    }
  }
};

// src/walletAdapterManager.ts
init_shim();
var WalletAdapterManager = class {
  constructor(walletAdapters) {
    this.walletAdapters = walletAdapters;
    if (!this.walletAdapters.length) {
      throw new Error("No wallet adapters provided");
    }
  }
  /**
   * return the current wallet adapter
   */
  get adapter() {
    return this._adapter;
  }
  get isEmpty() {
    return this.walletAdapters.length === 0;
  }
  /**
   * check if the current wallet adapter is exist
   */
  get isAdapterExist() {
    return !!this._adapter;
  }
  /**
   * set the current wallet adapter
   */
  switchWallet(chainNamespace, address, chainId, options) {
    const adapter = this.walletAdapters.find(
      (adapter2) => adapter2.chainNamespace === chainNamespace.toUpperCase()
    );
    if (!adapter) {
      throw new Error("Unsupported chain namespace");
    }
    const config = {
      address,
      chain: { id: chainId },
      provider: options.provider,
      contractManager: options.contractManager
    };
    if (this._adapter) {
      if (this._adapter === adapter) {
        this._adapter.update(config);
        return;
      } else {
        this._adapter.deactivate();
      }
    }
    this._adapter = adapter;
    this._adapter.active(config);
  }
  get chainId() {
    return this.adapter?.chainId;
  }
};

